--[[ ============================================================================
  SAMPLE 10  --  CoS HUB  --  FULLY SOLVED SINGLE-FILE (research artifact)
  ============================================================================

  100% plain Lua. ZERO Luraph machinery (no LPH$ base85 blob, no LZMA
  decompressor, no chunk 2 dispatcher). Both decompressed payloads that the
  original Luraph 14.6 chunk-2 dispatcher produced have been extracted and
  inlined:

    1. chunk-3 source (the plain-Lua VM, mangled names J/w/z/F/o/B/q)
       -- captured by intercepting loadstring() inside a patched chunk 2 run
       -- 83,626 bytes, matches the body of chunk3_normalized.lua exactly
    2. y-blob (the binary constants / bytecode stream that chunk 3 reads via
       string.unpack and string.sub)
       -- captured as the single string vararg chunk 2 hands to chunk 3
       -- 607,121 bytes, embedded below as a Lua long-string

  WHAT WAS RESOLVED IN THIS BUILD vs. earlier sample10_offline.lua
  ----------------------------------------------------------------------------
  * Chunk 2 dispatcher: ELIMINATED. We no longer carry its 401 KB Luraph
    source. The two outputs it produced at runtime are inlined directly.
  * LPH$ base85 blob: ELIMINATED.
  * LZMA-style range-coder decompressor (function K, ~200 lines): ELIMINATED.
  * Base85 ASCII decoder (function v, ~10 lines): ELIMINATED.
  * Magic constants table R[1..9] / RC4 sanity checks: ELIMINATED.

  REMAINING MANGLED NAMES (info-theoretic floor)
  ----------------------------------------------------------------------------
  Chunk 3's variable names J/w/z/F/o/B/q remain single-letter. Luraph 14.6
  compile pipeline strips upstream names at the bytecode-compile step (the
  one before LPH$ encoding). They are not recoverable from any static form
  of the payload. The CONTROL FLOW and LITERAL STRINGS are intact and
  readable.

  KEYSYSTEM
  ----------------------------------------------------------------------------
  Sample 10 has no user-facing keysystem. The original chunk-1 loader set
  getgenv().SCRIPT_KEY = "" (empty string) -- pure formality. We do NOT set
  it. Server-side gating was via the jnkie CDN URL-hash path, which is not
  exercised by this offline build.

  MOBILE EXECUTOR COMPAT
  ----------------------------------------------------------------------------
  Delta Mobile / Codex / Hydrogen / Arceus X / Fluxus Android / KRNL Mobile /
  Cryptic / Trigon / Solara Mobile / Evon Mobile -- all polyfilled below
  (loadstring/load/getgenv/bit32/setfenv).

  PARSES WITH: tools/lua53/luac53.exe -p sample10_solved.lua  --> OK
============================================================================ ]]

-- 1. Mobile compat preamble ---------------------------------------------------
do
    if type(rawget(_G, "loadstring")) ~= "function" and type(rawget(_G, "load")) == "function" then
        rawset(_G, "loadstring", rawget(_G, "load"))
    end
    if type(rawget(_G, "load")) ~= "function" and type(rawget(_G, "loadstring")) == "function" then
        rawset(_G, "load", rawget(_G, "loadstring"))
    end
    if type(rawget(_G, "getgenv")) ~= "function" then
        rawset(_G, "getgenv", function() return _G end)
    end
    if type(rawget(_G, "setfenv")) ~= "function" then
        rawset(_G, "setfenv", function(fn, _env) return fn end)
    end
    if type(rawget(_G, "getfenv")) ~= "function" then
        rawset(_G, "getfenv", function() return _G end)
    end
    if type(rawget(_G, "bit32")) ~= "table" then
        local b = {}
        b.band   = function(a, c) return a & c end
        b.bor    = function(a, c) return a | c end
        b.bxor   = function(a, c) return a ~ c end
        b.bnot   = function(a)    return ~a & 0xFFFFFFFF end
        b.lshift = function(a, n) return (a << n) & 0xFFFFFFFF end
        b.rshift = function(a, n) return (a & 0xFFFFFFFF) >> n end
        b.arshift= function(a, n) return a >> n end
        rawset(_G, "bit32", b)
    end
    pcall(warn, "[sample10] solved-build loaded (no LPH$, no keysystem)")
end

-- 2. bit32 / buffer polyfill (from chunk3_normalized.lua's own prelude) ------
do
    local _bit32 = rawget(_G, 'bit32') or {}
    rawset(_G, 'bit32', _bit32)
    local function _to_u32(x) return x & 0xFFFFFFFF end
    if not _bit32.band     then _bit32.band     = function(...) local a=0xFFFFFFFF; for _,v in ipairs({...}) do a = a & (v or 0xFFFFFFFF) end; return _to_u32(a) end end
    if not _bit32.bor      then _bit32.bor      = function(...) local a=0; for _,v in ipairs({...}) do a = a | (v or 0) end; return _to_u32(a) end end
    if not _bit32.bxor     then _bit32.bxor     = function(...) local a=0; for _,v in ipairs({...}) do a = a ~ (v or 0) end; return _to_u32(a) end end
    if not _bit32.bnot     then _bit32.bnot     = function(a)   return _to_u32(~a) end end
    if not _bit32.lshift   then _bit32.lshift   = function(a,b) return _to_u32((a & 0xFFFFFFFF) << (b & 31)) end end
    if not _bit32.rshift   then _bit32.rshift   = function(a,b) return _to_u32((a & 0xFFFFFFFF) >> (b & 31)) end end
    if not _bit32.arshift  then _bit32.arshift  = function(a,b)
        a = a & 0xFFFFFFFF; b = b & 31
        if a < 0x80000000 then return a >> b end
        local s = a >> b
        s = s | (((1<<b) - 1) << (32 - b))
        return _to_u32(s)
    end end
    if not _bit32.lrotate  then _bit32.lrotate  = function(a,b) a = a & 0xFFFFFFFF; b = b & 31; return _to_u32(((a << b) | (a >> (32-b)))) end end
    if not _bit32.rrotate  then _bit32.rrotate  = function(a,b) a = a & 0xFFFFFFFF; b = b & 31; return _to_u32(((a >> b) | (a << (32-b)))) end end
    if not _bit32.btest    then _bit32.btest    = function(a,b) return (a & b) ~= 0 end end
    if not _bit32.extract  then _bit32.extract  = function(a,f,w) w=w or 1; return ((a>>f) & ((1<<w)-1)) end end
    if not _bit32.replace  then _bit32.replace  = function(a,v,f,w) w=w or 1; local m=((1<<w)-1)<<f; return _to_u32((a & ~m) | ((v<<f) & m)) end end
    if not _bit32.countlz  then _bit32.countlz  = function(a) a = a & 0xFFFFFFFF; if a==0 then return 32 end; local n=0; while (a & 0x80000000) == 0 do n=n+1; a=a<<1 end; return n end end
    if not _bit32.countrz  then _bit32.countrz  = function(a) a = a & 0xFFFFFFFF; if a==0 then return 32 end; local n=0; while (a & 1) == 0 do n=n+1; a=a>>1 end; return n end end
    if not _bit32.byteswap then _bit32.byteswap = function(a) a = a & 0xFFFFFFFF; return _to_u32(((a&0xFF)<<24) | ((a&0xFF00)<<8) | ((a>>8)&0xFF00) | ((a>>24)&0xFF)) end end
end
if not table.unpack then table.unpack = unpack end
if not unpack then unpack = table.unpack end

